1051→async function renderSceneWithLabels(title, wordDetails, aiImgUrl) {
1052→  const canvas = document.getElementById('imgCanvas');
1053→  const ctx = canvas.getContext('2d');
1054→  const W = 1024, H = 768;
1055→  canvas.width = W; canvas.height = H;
1056→
1057→  if (aiImgUrl) {
1058→    try {
1059→      const img = await loadImg(aiImgUrl);
1060→      ctx.drawImage(img, 0, 0, W, H);
1061→    } catch(e) {
1062→      drawFallbackBg(ctx, W, H, title);
1063→    }
1064→  } else {
1065→    drawFallbackBg(ctx, W, H, title);
1066→  }
1067→
1068→  // 半透明遮罩让标注更清晰
1069→  const grad = ctx.createLinearGradient(0, 0, 0, H);
1070→  grad.addColorStop(0, 'rgba(0,0,0,0.15)');
1071→  grad.addColorStop(0.4, 'rgba(0,0,0,0.05)');
1072→  grad.addColorStop(0.6, 'rgba(0,0,0,0.1)');
1073→  grad.addColorStop(1, 'rgba(0,0,0,0.55)');
1074→  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);
1075→
1076→  // 顶部标题
1077→  ctx.font = 'bold 24px Microsoft YaHei UI';
1078→  const tw = ctx.measureText('📚 ' + title).width + 40;
1079→  ctx.fillStyle = 'rgba(91,122,94,0.9)';
1080→  rrect(ctx, 20, 16, tw, 48, 24); ctx.fill();
1081→  ctx.fillStyle = '#fff'; ctx.textAlign = 'left';
1082→  ctx.fillText('📚 ' + title, 40, 48);
1083→
1084→  // 词汇标注卡片 - 散布在画面中
1085→  const n = wordDetails.length;
1086→  const cols = Math.min(3, n);
1087→  const rows = Math.ceil(n / cols);
1088→  const cardW = 300, cardH = 62, gapX = 16, gapY = 14;
1089→  const gridW = cols * (cardW + gapX) - gapX;
1090→  const gridH = rows * (cardH + gapY) - gapY;
1091→  const ox = (W - gridW) / 2;
1092→  const oy = H - gridH - 40;
1093→
1094→  for (let i = 0; i < n; i++) {
1095→    const wd = wordDetails[i];
1096→    const col = i % cols, row = Math.floor(i / cols);
1097→    const x = ox + col * (cardW + gapX);
1098→    const y = oy + row * (cardH + gapY);
1099→
1100→    // 卡片背景 - 白色圆角带阴影
1101→    ctx.shadowColor = 'rgba(0,0,0,0.3)'; ctx.shadowBlur = 10; ctx.shadowOffsetY = 3;
1102→    ctx.fillStyle = 'rgba(255,255,255,0.92)';
1103→    rrect(ctx, x, y, cardW, cardH, 12); ctx.fill();
1104→    ctx.shadowColor = 'transparent'; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;
1105→
1106→    // 左侧色条
1107→    ctx.fillStyle = '#5b7a5e';
1108→    rrect(ctx, x, y, 6, cardH, 3); ctx.fill();
1109→
1110→    // 序号圆
1111→    ctx.fillStyle = '#5b7a5e';
1112→    ctx.beginPath(); ctx.arc(x + 22, y + 20, 10, 0, Math.PI * 2); ctx.fill();
1113→    ctx.fillStyle = '#fff'; ctx.font = 'bold 11px Microsoft YaHei UI'; ctx.textAlign = 'center';
1114→    ctx.fillText(String(i + 1), x + 22, y + 24);
1115→
1116→    // 单词
1117→    ctx.fillStyle = '#1a1a1a'; ctx.font = 'bold 20px Microsoft YaHei UI'; ctx.textAlign = 'left';
1118→    ctx.fillText(wd.word, x + 40, y + 26);
1119→
1120→    // 中文释义
1121→    if (wd.translation) {
1122→      ctx.fillStyle = '#5b7a5e'; ctx.font = '14px Microsoft YaHei UI';
1123→      ctx.fillText(wd.translation.slice(0, 24), x + 40, y + 50);
1124→    }
1125→  }
1126→
1127→  // 底部水印
1128→  ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.font = '11px Microsoft YaHei UI'; ctx.textAlign = 'center';
1129→  ctx.fillText('多语言视频学习 · 词汇场景图', W / 2, H - 10);
1130→
1131→  return canvas.toDataURL('image/png');
1132→}
