// 监听语音识别状态 - 显示后3秒自动隐藏
let statusTimer = null;
ipcRenderer.on('subtitle-status', (_, msg) => {
  statusText.textContent = msg;
  subtitleText.textContent = msg;
  progressRow.style.display = 'flex';
  if (statusTimer) clearTimeout(statusTimer);
  // 完成/失败消息3秒后隐藏进度条
  if (msg.includes('完成') || msg.includes('失败') || msg.includes('已找到') || msg.includes('已加载')) {
    statusTimer = setTimeout(() => { progressRow.style.display = 'none'; }, 3000);
  }
});

// 后台转录完成后自动刷新字幕
ipcRenderer.on('subtitle-updated', async (_, vttPath) => {
  const vtt = await ipcRenderer.invoke('read-subtitle', vttPath);
  if (vtt) {
    const newSubs = parseVTT(vtt);
    if (newSubs.length > subtitles.length) {
      subtitles = newSubs;
      buildSubtitleList();
      subtitleText.textContent = `字幕已更新，共 ${subtitles.length} 条`;
    }
  }
  wordTimings = await ipcRenderer.invoke('read-word-timestamps', vttPath);
});

// 清除
document.getElementById('clearUrlBtn').addEventListener('click', () => { urlInput.value = ''; });

// 粘贴
pasteBtn.addEventListener('click', async () => {
  try {
    const text = await navigator.clipboard.readText();
    const m = text.match(/https?:\/\/[^\s"'<>]+/);
    urlInput.value = m ? m[0] : text.trim();
  } catch(e) {}
});

// 下载
downloadBtn.addEventListener('click', async () => {
  const url = urlInput.value.trim();
  if (!url) return;
  currentLang = langSelect.value;
  downloadBtn.disabled = true;
  progressRow.style.display = 'flex';
  progressFill.style.width = '0%';
  statusText.textContent = '正在下载...';
  const result = await ipcRenderer.invoke('download-video', url, currentLang);
  downloadBtn.disabled = false;
  if (result.success) {
    progressFill.style.width = '100%';
    statusText.textContent = '下载完成!';
    await refreshVideoList();
    if (result.videoPath) loadVideo(result.videoPath, result.subtitlePath);
  } else {
    statusText.textContent = '失败: ' + result.error;
  }
});

ipcRenderer.on('download-progress', (_, p) => {
  progressFill.style.width = p.percent + '%';
  statusText.textContent = `下载中 ${p.percent.toFixed(0)}%`;
});

// 视频列表
async function refreshVideoList() {
  const videos = await ipcRenderer.invoke('list-videos');
  videoSelect.innerHTML = '<option value="">-- 选择视频 --</option>';
  for (const v of videos) {
    const opt = document.createElement('option');
    opt.value = JSON.stringify(v); opt.textContent = v.name;
    videoSelect.appendChild(opt);
  }
}

videoSelect.addEventListener('change', () => {
  if (!videoSelect.value) return;
  loadVideo(...(v => [v.videoPath, v.subtitlePath])(JSON.parse(videoSelect.value)));
});

async function loadVideo(videoPath, subtitlePath) {
  playerArea.style.display = 'block';
  currentVideoPath = videoPath;
  videoPlayer.src = 'file:///' + videoPath.replace(/\\/g, '/');
  subtitles = []; currentSubIndex = -1; wordTimings = null;
  subtitleText.textContent = '加载字幕中...';
  aiAnalyzeBtn.style.display = 'none';
  aiResult.style.display = 'none';
  const subtitleList = document.getElementById('subtitleList');
  subtitleList.innerHTML = '';

  let loaded = false;
  // 优先尝试传入的字幕路径
  if (subtitlePath) {
    const vtt = await ipcRenderer.invoke('read-subtitle', subtitlePath);
    if (vtt) {
      subtitles = parseVTT(vtt);
      if (subtitles.length > 0) {
        buildSubtitleList();
        subtitleText.textContent = `已加载 ${subtitles.length} 条字幕，播放视频即可同步显示`;
        loaded = true;
      }
    }
  }
  // 没有传入字幕时，先检查同名.vtt是否已存在（之前转录过的）
  if (!loaded) {
    const existingVtt = await ipcRenderer.invoke('check-existing-subtitle', videoPath);
    if (existingVtt) {
      const vtt = await ipcRenderer.invoke('read-subtitle', existingVtt);
      if (vtt) {
        subtitles = parseVTT(vtt);
        if (subtitles.length > 0) {
          buildSubtitleList();
          subtitleText.textContent = `已加载 ${subtitles.length} 条字幕，播放视频即可同步显示`;
          loaded = true;
        }
      }
    }
  }
  // 都没有才启动语音识别
  if (!loaded) {
    subtitleText.textContent = '无字幕文件，正在启动语音识别...';
    const vttPath = await ipcRenderer.invoke('generate-subtitle', videoPath);
    if (vttPath) {
      const vtt = await ipcRenderer.invoke('read-subtitle', vttPath);
      if (vtt) {
        subtitles = parseVTT(vtt);
        if (subtitles.length > 0) {
          buildSubtitleList();
          subtitleText.textContent = `语音识别完成，已生成 ${subtitles.length} 条字幕`;
          loaded = true;
        }
      }
    }
    if (!loaded) subtitleText.textContent = '语音识别失败，请确认 funasr 服务已启动';
  }
  // 加载逐词时间戳（如果有）
  const vttFile = subtitlePath || await ipcRenderer.invoke('check-existing-subtitle', videoPath);
  if (vttFile) wordTimings = await ipcRenderer.invoke('read-word-timestamps', vttFile);
}

// VTT解析 (处理YouTube自动字幕的双行格式)
function parseVTT(vtt) {
  const raw = [];
  for (const block of vtt.split(/\n\n+/)) {
    const lines = block.trim().split('\n');
    for (let i = 0; i < lines.length; i++) {
      const m = lines[i].match(/(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})/);
      if (!m) continue;
      const start = +m[1]*3600 + +m[2]*60 + +m[3] + +m[4]/1000;
      const end = +m[5]*3600 + +m[6]*60 + +m[7] + +m[8]/1000;
      // 跳过极短条目(YouTube自动字幕的过渡帧)
      if (end - start < 0.05) break;
      // 取最后一行非空文本(YouTube双行字幕中新内容在最后一行)
      const textLines = lines.slice(i+1).map(l => l.replace(/<[^>]+>/g, '').trim()).filter(Boolean);
      const text = textLines.length > 0 ? textLines[textLines.length - 1] : '';
      if (text) raw.push({ start, end, text });
      break;
    }
  }
  // 合并连续相同文本，去重
  const result = [];
  for (const s of raw) {
    if (result.length > 0 && result[result.length-1].text === s.text) {
      result[result.length-1].end = s.end; // 延长时间
    } else {
      result.push({ ...s });
    }
  }
  return result;
}

// 字幕同步 (用setInterval确保可靠触发)
let syncTimer = null;
function startSubtitleSync() {
  if (syncTimer) clearInterval(syncTimer);
  syncTimer = setInterval(() => {
    if (!subtitles.length || currentMode !== 'learn' || videoPlayer.paused) return;
    const t = videoPlayer.currentTime;
    // 二分查找当前时间对应的字幕
    let lo = 0, hi = subtitles.length - 1, idx = -1;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (t >= subtitles[mid].start && t <= subtitles[mid].end) { idx = mid; break; }
      if (t < subtitles[mid].start) hi = mid - 1;
      else lo = mid + 1;
    }
    if (idx < 0) {
      // 在间隙中：找下一条即将出现的字幕（0.5秒内），或保持上一条
      for (let i = 0; i < subtitles.length; i++) {
        if (subtitles[i].start > t) {
          if (subtitles[i].start - t < 0.5) { idx = i; }
          else if (i > 0) { idx = i - 1; }
          break;
        }
      }
      if (idx < 0) idx = subtitles.length - 1; // 超过最后一条
    }
    if (idx !== currentSubIndex) {
      currentSubIndex = idx;
      currentSentence = subtitles[idx].text;
      renderSubtitle(currentSentence);
      aiAnalyzeBtn.style.display = 'inline-block';
      aiResult.style.display = 'none';
      highlightSubtitleList(idx);
    }
    // 卡拉OK式逐词点亮
    if (idx >= 0 && idx === currentSubIndex) {
      const sub = subtitles[idx];
      const words = subtitleText.querySelectorAll('.word');
      if (words.length > 0) {
        if (wordTimings) {
          // 精准模式：用逐词时间戳，按文本匹配对齐
          const subWords = wordTimings.filter(wt => wt.s >= sub.start - 0.1 && wt.s <= sub.end + 0.3);
          if (subWords.length > 0) {
            // 建立显示词 → wordTiming 的精准映射
            let wtIdx = 0;
            words.forEach((w) => {
              const displayed = w.textContent.trim().toLowerCase().replace(/[^\p{L}\p{M}\p{N}'-]/gu, '');
              // 向前搜索匹配的 wordTiming
              let matched = null;
              for (let k = wtIdx; k < subWords.length; k++) {
                const wtWord = subWords[k].w.trim().toLowerCase().replace(/[^\p{L}\p{M}\p{N}'-]/gu, '');
                if (wtWord === displayed || displayed.startsWith(wtWord) || wtWord.startsWith(displayed)) {
                  matched = subWords[k];
                  wtIdx = k + 1;
                  break;
                }
              }
              if (matched) {
                w.classList.toggle('word-lit', t >= matched.s && t < matched.e);
                w.classList.toggle('word-past', t >= matched.e);
              } else {
                // 无匹配时不高亮
                w.classList.remove('word-lit', 'word-past');
              }
            });
          } else {
            fallbackHighlight(words, t, sub);
          }
        } else {
          fallbackHighlight(words, t, sub);
        }
      }
    }
  }, 30);
}
videoPlayer.addEventListener('play', startSubtitleSync);

function fallbackHighlight(words, t, sub) {
  const elapsed = t - sub.start;
  const dur = sub.end - sub.start;
  if (dur <= 0 || elapsed < 0) return;
  const lens = Array.from(words).map(w => Math.max(w.textContent.length, 1));
  const total = lens.reduce((a, b) => a + b, 0);
  let cum = 0, activeIdx = words.length - 1;
  for (let i = 0; i < lens.length; i++) {
    cum += (lens[i] / total) * dur;
    if (elapsed < cum) { activeIdx = i; break; }
  }
  words.forEach((w, i) => {
    w.classList.toggle('word-lit', i === activeIdx);
    w.classList.toggle('word-past', i < activeIdx);
  });
}
videoPlayer.addEventListener('seeked', () => { currentSubIndex = -1; });

// 重新转录
let currentVideoPath = null;
document.getElementById('retranscribeBtn').addEventListener('click', async () => {
  if (!currentVideoPath) return;
  videoPlayer.pause();
  await ipcRenderer.invoke('delete-subtitle', currentVideoPath);
  subtitles = []; currentSubIndex = -1; wordTimings = null;
  subtitleText.textContent = '正在重新转录...';
  document.getElementById('subtitleList').innerHTML = '';
  const vttPath = await ipcRenderer.invoke('generate-subtitle', currentVideoPath);
  if (vttPath) {
    const vtt = await ipcRenderer.invoke('read-subtitle', vttPath);
    if (vtt) {
      subtitles = parseVTT(vtt);
      if (subtitles.length > 0) {
        buildSubtitleList();
        subtitleText.textContent = `重新转录完成，共 ${subtitles.length} 条字幕`;
        wordTimings = await ipcRenderer.invoke('read-word-timestamps', vttPath);
      }
    }
  }
  if (!subtitles.length) subtitleText.textContent = '转录失败';
});

// 点击字幕区域外恢复播放
subtitleArea.addEventListener('click', (e) => {
  if (!e.target.classList.contains('word') && !wordInlinePanel.contains(e.target)) {
    videoPlayer.play();
  }
});

function renderSubtitle(text) {
  subtitleText.innerHTML = '';
  wordInlinePanel.style.display = 'none';
  const displayedWords = text.split(/(\s+)/).filter(w => !/^\s*$/.test(w));
  // 预计算当前字幕对应的 wordTimings 映射
  const sub = subtitles[currentSubIndex];
  let wtMap = [];
  if (wordTimings && sub) {
    const subWords = wordTimings.filter(wt => wt.s >= sub.start - 0.1 && wt.s <= sub.end + 0.3);
    let wtIdx = 0;
    for (const dw of displayedWords) {
      const clean = dw.trim().toLowerCase().replace(/[^\p{L}\p{M}\p{N}'-]/gu, '');
      let matched = null;
      for (let k = wtIdx; k < subWords.length; k++) {
        const wtWord = subWords[k].w.trim().toLowerCase().replace(/[^\p{L}\p{M}\p{N}'-]/gu, '');
        if (wtWord === clean || clean.startsWith(wtWord) || wtWord.startsWith(clean)) {
          matched = subWords[k];
          wtIdx = k + 1;
          break;
        }
      }
      wtMap.push(matched);
    }
  }

  let wordIdx = 0;
  for (const w of text.split(/(\s+)/)) {
    if (/^\s+$/.test(w)) { subtitleText.appendChild(document.createTextNode(' ')); continue; }
    const span = document.createElement('span');
    span.className = 'word'; span.textContent = w;
    const wt = wtMap[wordIdx] || null;
    span.addEventListener('click', (e) => {
      e.stopPropagation();
      // 点击单词跳转到该词的精准时间
      if (wt) {
        videoPlayer.currentTime = wt.s;
        videoPlayer.pause();
      } else {
        videoPlayer.pause();
      }
      const sel = window.getSelection().toString().trim();
      if (sel && sel.includes(' ')) {
        showWordInline(sel);
      } else {
        const clean = cleanWord(w);
        if (clean) showWordInline(clean);
      }
    });
    subtitleText.appendChild(span);
    wordIdx++;
  }
}

// 短语选择：鼠标抬起时检测选中文本，显示收藏短语按钮
document.addEventListener('mouseup', (e) => {
  const old = document.getElementById('phraseCollectBtn');
  if (old) old.remove();
  const sel = window.getSelection().toString().trim();
  if (!sel || sel.length < 2 || !subtitleText.contains(window.getSelection().anchorNode)) return;
  const btn = document.createElement('button');
  btn.id = 'phraseCollectBtn';
  btn.className = 'btn btn-small phrase-collect-btn';
  btn.textContent = sel.includes(' ') ? '☆ 收藏短语' : '☆ 收藏';
  btn.style.cssText = `position:fixed;left:${e.clientX+5}px;top:${e.clientY-35}px;z-index:5000;`;
  btn.addEventListener('click', async () => {
    await ipcRenderer.invoke('fav-add', sel, currentLang, '', '', currentSentence || '');
    btn.textContent = '★ 已收藏';
    btn.style.color = '#ff0000';
    setTimeout(() => btn.remove(), 800);
  });
  document.body.appendChild(btn);
  setTimeout(() => { if (btn.parentNode) btn.remove(); }, 4000);
});

function cleanWord(w) {
  return w.replace(/[^\p{L}\p{M}'-]/gu, '');
}

// 字幕滚动列表
function formatTime(s) {
  const m = Math.floor(s / 60), sec = Math.floor(s % 60);
  return m + ':' + String(sec).padStart(2, '0');
}

function buildSubtitleList() {
  const list = document.getElementById('subtitleList');
  list.innerHTML = '';
  subtitles.forEach((s, i) => {
    const row = document.createElement('div');
    row.className = 'sub-list-item';
    row.dataset.idx = i;
    row.innerHTML = `<span class="sub-time">${formatTime(s.start)}</span><span class="sub-content">${s.text}</span>`;
    row.addEventListener('click', () => {
      videoPlayer.currentTime = s.start;
      videoPlayer.play();
    });
    list.appendChild(row);
  });
}

function highlightSubtitleList(idx) {
  const list = document.getElementById('subtitleList');
  list.querySelectorAll('.sub-list-item').forEach(el => el.classList.remove('active'));
  const active = list.querySelector(`[data-idx="${idx}"]`);
  if (active) {
    active.classList.add('active');
    active.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }
}

// AI分析句子
aiAnalyzeBtn.addEventListener('click', async () => {
  if (!currentSentence) return;
  aiResult.style.display = 'block';
  aiResult.textContent = '🤖 AI分析中...';
  const result = await ipcRenderer.invoke('ai-analyze-sentence', currentSentence, currentLang);
  aiResult.textContent = result || 'AI未配置或请求失败，请在设置中配置API Key';
});

