async function renderSceneWithLabels(title, wordDetails, aiImgUrl) {
  const canvas = document.getElementById('imgCanvas');
  const ctx = canvas.getContext('2d');
  const W = 1024, H = 768;
  canvas.width = W; canvas.height = H;

  if (aiImgUrl) {
    try {
      const img = await loadImg(aiImgUrl);
      ctx.drawImage(img, 0, 0, W, H);
    } catch(e) {
      drawFallbackBg(ctx, W, H, title);
    }
  } else {
    drawFallbackBg(ctx, W, H, title);
  }

  // 半透明遮罩让标注更清晰
  const grad = ctx.createLinearGradient(0, 0, 0, H);
  grad.addColorStop(0, 'rgba(0,0,0,0.15)');
  grad.addColorStop(0.4, 'rgba(0,0,0,0.05)');
  grad.addColorStop(0.6, 'rgba(0,0,0,0.1)');
  grad.addColorStop(1, 'rgba(0,0,0,0.55)');
  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);

  // 顶部标题
  ctx.font = 'bold 24px Microsoft YaHei UI';
  const tw = ctx.measureText('📚 ' + title).width + 40;
  ctx.fillStyle = 'rgba(91,122,94,0.9)';
  rrect(ctx, 20, 16, tw, 48, 24); ctx.fill();
  ctx.fillStyle = '#fff'; ctx.textAlign = 'left';
  ctx.fillText('📚 ' + title, 40, 48);

  // 词汇标注卡片 - 散布在画面中
  const n = wordDetails.length;
  const cols = Math.min(3, n);
  const rows = Math.ceil(n / cols);
  const cardW = 300, cardH = 62, gapX = 16, gapY = 14;
  const gridW = cols * (cardW + gapX) - gapX;
  const gridH = rows * (cardH + gapY) - gapY;
  const ox = (W - gridW) / 2;
  const oy = H - gridH - 40;

  for (let i = 0; i < n; i++) {
    const wd = wordDetails[i];
    const col = i % cols, row = Math.floor(i / cols);
    const x = ox + col * (cardW + gapX);
    const y = oy + row * (cardH + gapY);

    // 卡片背景 - 白色圆角带阴影
    ctx.shadowColor = 'rgba(0,0,0,0.3)'; ctx.shadowBlur = 10; ctx.shadowOffsetY = 3;
    ctx.fillStyle = 'rgba(255,255,255,0.92)';
    rrect(ctx, x, y, cardW, cardH, 12); ctx.fill();
    ctx.shadowColor = 'transparent'; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;

    // 左侧色条
    ctx.fillStyle = '#5b7a5e';
    rrect(ctx, x, y, 6, cardH, 3); ctx.fill();

    // 序号圆
    ctx.fillStyle = '#5b7a5e';
    ctx.beginPath(); ctx.arc(x + 22, y + 20, 10, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#fff'; ctx.font = 'bold 11px Microsoft YaHei UI'; ctx.textAlign = 'center';
    ctx.fillText(String(i + 1), x + 22, y + 24);

    // 单词
    ctx.fillStyle = '#1a1a1a'; ctx.font = 'bold 20px Microsoft YaHei UI'; ctx.textAlign = 'left';
    ctx.fillText(wd.word, x + 40, y + 26);

    // 中文释义
    if (wd.translation) {
      ctx.fillStyle = '#5b7a5e'; ctx.font = '14px Microsoft YaHei UI';
      ctx.fillText(wd.translation.slice(0, 24), x + 40, y + 50);
    }
  }

  // 底部水印
  ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.font = '11px Microsoft YaHei UI'; ctx.textAlign = 'center';
  ctx.fillText('多语言视频学习 · 词汇场景图', W / 2, H - 10);

  return canvas.toDataURL('image/png');
}

function drawFallbackBg(ctx, W, H, title) {
  // 丰富的渐变背景
  const colors = [
    ['#667eea', '#764ba2'], ['#f093fb', '#f5576c'], ['#4facfe', '#00f2fe'],
    ['#43e97b', '#38f9d7'], ['#fa709a', '#fee140'], ['#a18cd1', '#fbc2eb']
  ];
  const pair = colors[Math.abs(title.charCodeAt(0)) % colors.length];
  const grad = ctx.createLinearGradient(0, 0, W, H);
  grad.addColorStop(0, pair[0]); grad.addColorStop(1, pair[1]);
  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);

  // 装饰元素 - 大圆、小圆、波浪
  ctx.globalAlpha = 0.12;
  for (let i = 0; i < 8; i++) {
    const cx = Math.random() * W, cy = Math.random() * H * 0.7, r = 40 + Math.random() * 100;
    ctx.fillStyle = '#fff';
    ctx.beginPath(); ctx.arc(cx, cy, r, 0, Math.PI * 2); ctx.fill();
  }
  // 底部波浪
  ctx.fillStyle = 'rgba(255,255,255,0.15)';
  ctx.beginPath(); ctx.moveTo(0, H * 0.65);
  for (let x = 0; x <= W; x += 20) {
    ctx.lineTo(x, H * 0.65 + Math.sin(x * 0.015) * 30 + Math.sin(x * 0.008) * 20);
  }
  ctx.lineTo(W, H); ctx.lineTo(0, H); ctx.fill();
  ctx.globalAlpha = 1;
}

function rrect(ctx, x, y, w, h, r) {
  ctx.beginPath(); ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r); ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h); ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r); ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y); ctx.closePath();
}
