// 语音识别生成字幕 (调用本地 funasr 服务)
const FUNASR_PYTHON = path.join(require('os').homedir(), 'funasr-venv', 'Scripts', 'python.exe');
const FUNASR_SERVER = path.join(require('os').homedir(), '.clawdbot', 'skills', 'funasr-transcribe', 'scripts', 'server.py');
let funasrProcess = null;

function checkFunasr() {
  return new Promise((resolve) => {
    const req = http.request({ hostname: '127.0.0.1', port: 8765, path: '/health', method: 'GET', timeout: 3000 }, (res) => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => resolve(true));
    });
    req.on('error', () => resolve(false));
    req.on('timeout', () => { req.destroy(); resolve(false); });
    req.end();
  });
}

function sendSubtitleStatus(msg) {
  if (mainWindow && !mainWindow.isDestroyed()) mainWindow.webContents.send('subtitle-status', msg);
}

async function ensureFunasr() {
  if (await checkFunasr()) return true;
  sendSubtitleStatus('正在启动语音识别服务...');
  // 启动服务
  if (fs.existsSync(FUNASR_PYTHON) && fs.existsSync(FUNASR_SERVER)) {
    funasrProcess = spawn(FUNASR_PYTHON, [FUNASR_SERVER], { stdio: 'ignore', detached: true });
    funasrProcess.unref();
    // 等待服务就绪，最多60秒
    for (let i = 0; i < 60; i++) {
      await new Promise(r => setTimeout(r, 1000));
      if (await checkFunasr()) {
        sendSubtitleStatus('语音识别服务已就绪');
        return true;
      }
      sendSubtitleStatus(`正在启动语音识别服务... (${i + 1}s)`);
    }
  }
  sendSubtitleStatus('语音识别服务启动失败');
  return false;
}

function transcribeFile(filePath) {
  return new Promise((resolve) => {
    const data = JSON.stringify({ file_path: filePath });
    const req = http.request({
      hostname: '127.0.0.1', port: 8765, path: '/transcribe',
      method: 'POST', headers: { 'Content-Type': 'application/json' }
    }, (res) => {
      let body = '';
      res.on('data', d => body += d);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(600000, () => { req.destroy(); resolve(null); });
    req.write(data);
    req.end();
  });
}

const SEGMENT_DURATION = 600; // 10分钟一段
const FOREGROUND_LIMIT = 2400; // 40分钟前台转录

// 通过Python调用Groq Whisper（绕过Node.js https被Groq拒绝的问题）
function transcribeGroqPython(audioPath, lang) {
  return new Promise((resolve) => {
    const tc = loadTranslateConfig();
    const aiCfg = loadAIConfig();
    const groqKey = aiCfg.groqWhisperKey || tc.groq_key || (aiCfg.provider === 'groq' ? aiCfg.apiKey : '');
    if (!groqKey) { resolve(null); return; }
    const wModel = aiCfg.whisperModel || 'whisper-large-v3';
    const langArg = lang || '';
    const script = `
import sys, json, requests, pathlib
f = pathlib.Path(sys.argv[1])
key = sys.argv[2]
lang = sys.argv[3] if len(sys.argv) > 3 and sys.argv[3] else None
wmodel = sys.argv[4] if len(sys.argv) > 4 and sys.argv[4] else "whisper-large-v3"
data = {"model": wmodel, "response_format": "verbose_json", "timestamp_granularities[]": ["word", "segment"], "temperature": "0"}
if lang:
    data["language"] = lang
data["prompt"] = "Transcribe accurately with proper punctuation and capitalization."
with open(f, "rb") as fh:
    r = requests.post("https://api.groq.com/openai/v1/audio/transcriptions",
        headers={"Authorization": f"Bearer {key}"},
        files={"file": (f.name, fh, "application/octet-stream")},
        data=data, timeout=300)
if r.status_code == 200:
    j = r.json()
    words = j.get("words", [])
    segs = j.get("segments", [])
    if words:
        wt = [{"w": w.get("word",""), "s": round(w.get("start",0)*1000), "e": round(w.get("end",0)*1000)} for w in words]
        print(json.dumps({"success": True, "text": j.get("text",""), "words": wt, "timestamp": [[w["s"], w["e"]] for w in wt], "detectedLang": j.get("language","")}))
    else:
        ts = [[int(s.get("start",0)*1000), int(s.get("end",0)*1000)] for s in segs]
        print(json.dumps({"success": True, "text": j.get("text",""), "words": [], "timestamp": ts, "detectedLang": j.get("language","")}))
else:
    print(json.dumps({"success": False, "error": r.text[:200]}))
`;
    const p = spawn('python', ['-c', script, audioPath, groqKey, langArg, wModel]);
    let out = '';
    p.stdout.on('data', d => out += d);
    p.stderr.on('data', () => {});
    p.on('close', () => {
      try { resolve(JSON.parse(out)); } catch(e) { resolve(null); }
    });
    p.on('error', () => resolve(null));
  });
}

