// 本地 whisper 转录（回退方案，支持所有语言）
function transcribeLocalWhisper(audioPath, lang) {
  return new Promise((resolve) => {
    const aiCfg = loadAIConfig();
    const wModel = aiCfg.localWhisperModel || 'base';
    const langArg = lang || '';
    const script = `
import sys, json, whisper
model = whisper.load_model(sys.argv[2])
opts = {"fp16": False, "word_timestamps": True}
if sys.argv[3]:
    opts["language"] = sys.argv[3]
r = model.transcribe(sys.argv[1], **opts)
segs = r.get("segments", [])
ts = [[int(s["start"]*1000), int(s["end"]*1000)] for s in segs]
# 尝试提取逐词时间戳
words = []
for s in segs:
    for w in s.get("words", []):
        words.append({"w": w.get("word","").strip(), "s": round(w.get("start",0)*1000), "e": round(w.get("end",0)*1000)})
print(json.dumps({"success": True, "text": r.get("text",""), "words": words, "timestamp": ts, "detectedLang": r.get("language","")}))
`;
    const p = spawn('python', ['-c', script, audioPath, wModel, langArg]);
    let out = '';
    p.stdout.on('data', d => out += d);
    p.stderr.on('data', () => {});
    p.on('close', () => {
      try { resolve(JSON.parse(out)); } catch(e) { resolve(null); }
    });
    p.on('error', () => resolve(null));
  });
}

// Whisper API 转录（支持所有语言，自动检测）
function transcribeWhisper(audioPath) {
  return new Promise((resolve) => {
    const cfg = loadAIConfig();
    if (!cfg.apiKey) { resolve(null); return; }

    // Groq 和 OpenAI 支持 Whisper
    let hostname, apiPath, apiKey;
    if (cfg.provider === 'groq') {
      hostname = 'api.groq.com'; apiPath = '/openai/v1/audio/transcriptions'; apiKey = cfg.apiKey;
    } else if (cfg.provider === 'openai') {
      hostname = 'api.openai.com'; apiPath = '/v1/audio/transcriptions'; apiKey = cfg.apiKey;
    } else {
      // 其他供应商不支持 Whisper，尝试用 OpenAI 兼容格式
      const baseUrl = cfg.baseUrl || AI_PROVIDERS[cfg.provider]?.baseUrl || '';
      if (!baseUrl) { resolve(null); return; }
      try {
        const u = new URL(baseUrl);
        hostname = u.hostname; apiPath = u.pathname.replace(/\/+$/, '') + '/audio/transcriptions'; apiKey = cfg.apiKey;
      } catch(e) { resolve(null); return; }
    }

    const boundary = '----FormBoundary' + Date.now();
    const audioData = fs.readFileSync(audioPath);
    const model = cfg.provider === 'groq' ? 'whisper-large-v3' : 'whisper-1';

    // multipart/form-data（不传language，让Whisper自动检测）
    const parts = [];
    parts.push(`--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="audio.wav"\r\nContent-Type: audio/wav\r\n\r\n`);
    parts.push(audioData);
    parts.push(`\r\n--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\n${model}`);
    parts.push(`\r\n--${boundary}\r\nContent-Disposition: form-data; name="response_format"\r\n\r\nverbose_json`);
    parts.push(`\r\n--${boundary}--\r\n`);

    const body = Buffer.concat(parts.map(p => typeof p === 'string' ? Buffer.from(p) : p));

    const req = https.request({
      hostname, port: 443, path: apiPath, method: 'POST',
      headers: {
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'Content-Length': body.length,
        'Authorization': 'Bearer ' + apiKey
      }
    }, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.text) {
            const words = json.words || json.segments || [];
            const timestamp = words.map(w => [Math.round((w.start || 0) * 1000), Math.round((w.end || 0) * 1000)]);
            resolve({ success: true, text: json.text, timestamp, detectedLang: json.language || null });
          } else { resolve(null); }
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(300000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });
}

ipcMain.handle('generate-subtitle', async (_, videoPath) => {
  // 重置语言检测
  detectedLanguage = null;

  // 已有字幕则直接返回
  const vttPath = videoPath.replace(/\.[^.]+$/, '.vtt');
  if (fs.existsSync(vttPath)) {
    const content = fs.readFileSync(vttPath, 'utf-8');
    if (content.includes('-->')) return vttPath;
  }

  // 检查 Whisper API 是否可用（Groq 或 OpenAI）
  const whisperAvailable = (() => {
    const cfg = loadAIConfig();
    return cfg.apiKey && (cfg.provider === 'groq' || cfg.provider === 'openai');
  })();
  // 检查 Groq key 是否可用且已启用
  const groqKeyAvailable = (() => {
    const cfg = loadAIConfig();
    if (cfg.groqWhisperEnabled === false) return false;
    const tc = loadTranslateConfig();
    if (cfg.groqWhisperKey || tc.groq_key) return true;
    return cfg.apiKey && cfg.provider === 'groq';
  })();

  sendSubtitleStatus('正在分析视频...');
  const ffprobe = path.join(FFMPEG_DIR, 'ffprobe.exe');
  const ffmpeg = path.join(FFMPEG_DIR, 'ffmpeg.exe');

  const duration = await new Promise((resolve) => {
    const p = spawn(ffprobe, ['-v', 'quiet', '-print_format', 'json', '-show_format', videoPath]);
    let out = '';
    p.stdout.on('data', d => out += d);
    p.on('close', () => {
      try { resolve(parseFloat(JSON.parse(out).format.duration) || 0); } catch(e) { resolve(0); }
    });
    p.on('error', () => resolve(0));
  });
  if (!duration) return null;

  const durationMin = Math.ceil(duration / 60);
  const segCount = Math.ceil(duration / SEGMENT_DURATION);
  const fgSegCount = Math.ceil(Math.min(duration, FOREGROUND_LIMIT) / SEGMENT_DURATION);
  const tmpDir = path.join(DOWNLOADS, '_tmp_segments');
  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });

  // 转录指定范围的段落，返回 {vttText, allText}
  async function transcribeRange(startSeg, endSeg) {
    let allText = '', vtt = '', wordTimings = [];
    let segTimes = [];
    const totalSegs = endSeg - startSeg;
    for (let i = startSeg; i < endSeg; i++) {
      const segStart = Date.now();
      const startSec = i * SEGMENT_DURATION;
      const segFile = path.join(tmpDir, `seg_${i}.wav`);
      const done = i - startSeg;
      const remaining = endSeg - i;

      let etaStr = '';
      if (segTimes.length > 0) {
        const avgMs = segTimes.reduce((a,b)=>a+b,0) / segTimes.length;
        const etaMin = Math.ceil(avgMs * remaining / 60000);
        const etaSec = Math.ceil(avgMs * remaining / 1000);
        etaStr = etaSec < 120 ? `，预计剩余 ${etaSec} 秒` : `，预计剩余 ${etaMin} 分钟`;
      }
      const progressStr = `[${done}/${totalSegs}]`;

      sendSubtitleStatus(`${progressStr} 提取音频 ${i + 1}/${segCount}${etaStr}`);
      const extractOk = await new Promise((resolve) => {
        const p = spawn(ffmpeg, ['-y', '-ss', String(startSec), '-t', String(SEGMENT_DURATION), '-i', videoPath, '-vn', '-ar', '16000', '-ac', '1', '-f', 'wav', segFile]);
        p.on('close', code => resolve(code === 0));
        p.on('error', () => resolve(false));
      });
      if (!extractOk) continue;

      let result;

      const statusBase = `${progressStr} 转录 ${i + 1}/${segCount}${etaStr}`;

      // 检测语言后更新前端
      function handleLangDetect(result) {
        if (result && result.success && result.detectedLang && !detectedLanguage) {
          const rawLang = result.detectedLang.toLowerCase();
          detectedLanguage = LANG_NAME_TO_CODE[rawLang] || rawLang;
          currentLangGlobal = detectedLanguage;
          const langName = LANGUAGES[detectedLanguage]?.name || result.detectedLang;
          sendSubtitleStatus(`${statusBase} - 检测到${langName}`);
          if (mainWindow && !mainWindow.isDestroyed()) {
            mainWindow.webContents.send('lang-detected', detectedLanguage);
          }
        }
      }

      // 优先级1: Groq Whisper API
      if (groqKeyAvailable) {
        sendSubtitleStatus(`${statusBase} [Groq]`);
        result = await transcribeGroqPython(segFile, null);
        handleLangDetect(result);
      }
      // 优先级2: 本地 whisper（支持所有语言）
      if (!result || !result.success) {
        sendSubtitleStatus(`${statusBase} [本地Whisper]`);
        result = await transcribeLocalWhisper(segFile, null);
        handleLangDetect(result);
      }
      // 优先级3: FunASR（仅中文）
      if (!result || !result.success) {
        if (!detectedLanguage || detectedLanguage === 'zh' || detectedLanguage === 'chinese') {
          sendSubtitleStatus(`${statusBase} [FunASR]`);
          const ok = await ensureFunasr();
          if (ok) result = await transcribeFile(segFile);
        }
      }
      try { fs.unlinkSync(segFile); } catch(e) {}
      segTimes.push(Date.now() - segStart);

      if (!result || !result.success || !result.text) continue;

      const text = result.text;
      const timestamps = result.timestamp || [];
      const apiWords = result.words || []; // Groq word-level timestamps

      if (apiWords.length > 0) {
        // === 精准模式：直接使用 Whisper 返回的逐词时间戳 ===
        // 按句子分组（遇到句末标点切分）
        let sentences = [], curWords = [];
        for (const aw of apiWords) {
          curWords.push(aw);
          const w = aw.w.trim();
          if (/[.!?。！？]$/.test(w) && curWords.length > 0) {
            sentences.push([...curWords]);
            curWords = [];
          }
        }
        if (curWords.length > 0) sentences.push(curWords);

        for (const sentWords of sentences) {
          const sentText = sentWords.map(w => w.w).join(' ').replace(/\s+/g, ' ').trim();
          const sStart = sentWords[0].s / 1000;
          const sEnd = sentWords[sentWords.length - 1].e / 1000;
          vtt += `${fmtVTT(startSec + sStart)} --> ${fmtVTT(startSec + sEnd)}\n${sentText}\n\n`;

          // 逐词时间戳：直接用 API 返回的精准时间，词文本也直接用 API 的
          for (const aw of sentWords) {
            wordTimings.push({
              w: aw.w.trim(),
              s: +(startSec + aw.s / 1000).toFixed(3),
              e: +(startSec + aw.e / 1000).toFixed(3)
            });
          }
        }
      } else if (timestamps.length > 0) {
        // === 回退模式：segment-level timestamps，按字符比例估算 ===
        const noSpace = text.replace(/\s/g, '');
        let sentences = [];
        let lastPos = 0, charCount = 0;
        for (let j = 0; j < text.length; j++) {
          if (/\s/.test(text[j])) continue;
          charCount++;
          if (/[.!?。！？]/.test(text[j])) {
            const s = text.slice(lastPos, j + 1).trim();
            const charEnd = charCount;
            const charStart = charEnd - s.replace(/\s/g, '').length;
            if (s) sentences.push({ text: s, charStart, charEnd });
            lastPos = j + 1;
          }
        }
        if (lastPos < text.length) {
          const s = text.slice(lastPos).trim();
          if (s) sentences.push({ text: s, charStart: charCount - s.replace(/\s/g, '').length, charEnd: charCount });
        }
        if (!sentences.length) sentences.push({ text, charStart: 0, charEnd: noSpace.length });

        const totalChars = noSpace.length;
        const totalTs = timestamps.length;

        for (const sent of sentences) {
          const tsStart = Math.floor(sent.charStart / totalChars * totalTs);
          const tsEnd = Math.min(Math.floor(sent.charEnd / totalChars * totalTs), totalTs - 1);
          const startMs = timestamps[tsStart] ? timestamps[tsStart][0] : 0;
          const endMs = timestamps[tsEnd] ? timestamps[tsEnd][1] : startMs + 1000;
          const start = fmtVTT(startSec + startMs / 1000);
          const end = fmtVTT(startSec + endMs / 1000);
          vtt += `${start} --> ${end}\n${sent.text}\n\n`;

          const words = sent.text.split(/(\s+)/).filter(w => !/^\s*$/.test(w));
          let charPos = sent.charStart;
          for (const w of words) {
            const wLen = w.replace(/\s/g, '').length;
            const wTsStart = Math.floor(charPos / totalChars * totalTs);
            const wTsEnd = Math.min(Math.floor((charPos + wLen) / totalChars * totalTs), totalTs - 1);
            const wStartMs = timestamps[wTsStart] ? timestamps[wTsStart][0] : 0;
            const wEndMs = timestamps[wTsEnd] ? timestamps[wTsEnd][1] : wStartMs + 200;
            wordTimings.push({
              w, s: +(startSec + wStartMs / 1000).toFixed(3), e: +(startSec + wEndMs / 1000).toFixed(3)
            });
            charPos += wLen;
          }
        }
      } else {
        const sentences = (text.match(/[^.!?。！？]+[.!?。！？]+/g) || [text]).map(s => s.trim()).filter(s => s.length > 0);
        if (!sentences.length) { allText += text; continue; }
        const segDur = Math.min(SEGMENT_DURATION, duration - startSec);
        const totalLen = sentences.reduce((a, s) => a + s.length, 0);
        let t = startSec;
        for (const s of sentences) {
          const seg = (s.length / totalLen) * segDur;
          const start = fmtVTT(t);
          t += seg;
          const end = fmtVTT(t);
          vtt += `${start} --> ${end}\n${s}\n\n`;
        }
      }
      allText += text;
    }

    // 根据用户设置决定是否翻译字幕
    const aiCfgTrans = loadAIConfig();
    const translateMode = aiCfgTrans.subtitleTranslateMode || 'none';
    const needTranslate = translateMode !== 'none' && detectedLanguage && detectedLanguage !== 'zh' && detectedLanguage !== 'chinese';

    if (needTranslate && vtt) {
      sendSubtitleStatus('正在翻译为中文...');
      const lines = vtt.split('\n');
      const textLines = [];
      const textIndices = [];
      for (let li = 0; li < lines.length; li++) {
        const line = lines[li];
        if (line.trim() && !line.includes('-->') && !/^\d+$/.test(line.trim())) {
          textLines.push(line.trim());
          textIndices.push(li);
        }
      }
      const translated = {};

      if (translateMode === 'ai') {
        // AI 大模型批量翻译
        const BATCH = 20;
        let pos = 0;
        while (pos < textLines.length) {
          const chunk = textLines.slice(pos, pos + BATCH);
          const start = pos;
          pos += chunk.length;
          const numbered = chunk.map((t, i) => `${i + 1}. ${t}`).join('\n');
          sendSubtitleStatus(`正在翻译为中文... (${Math.min(pos, textLines.length)}/${textLines.length})`);
          const langName = LANGUAGES[detectedLanguage]?.name || detectedLanguage;
          const result = await callAI(`将以下${langName}字幕逐行译为中文，保持行号格式"序号. 中文"：\n${numbered}`);
          if (result) {
            for (const rl of result.trim().split('\n')) {
              const m = rl.match(/^(\d+)\.\s*(.+)/);
              if (m) {
                const idx = parseInt(m[1]) - 1;
                if (idx >= 0 && idx < chunk.length) translated[textIndices[start + idx]] = m[2].trim();
              }
            }
          }
        }
      } else if (translateMode === 'baidu') {
        // 百度翻译批量
        const MAX_CHARS = 4000;
        let pos = 0;
        while (pos < textLines.length) {
          let chunk = [], chunkLen = 0, start = pos;
          while (pos < textLines.length && chunkLen + textLines[pos].length < MAX_CHARS) {
            chunk.push(textLines[pos]); chunkLen += textLines[pos].length + 1; pos++;
          }
          if (!chunk.length) { chunk.push(textLines[pos]); pos++; }
          sendSubtitleStatus(`正在翻译为中文... (${Math.min(pos, textLines.length)}/${textLines.length})`);
          const result = await baiduTranslate(chunk.join('\n'), detectedLanguage || 'auto');
          if (result) {
            const resultLines = result.split('\n');
            for (let j = 0; j < chunk.length; j++) {
              if (resultLines[j]) translated[textIndices[start + j]] = resultLines[j];
            }
          }
          await new Promise(r => setTimeout(r, 1100));
        }
      }

      // 重建VTT，在原文后插入中文
      let newVtt = '';
      for (let li = 0; li < lines.length; li++) {
        newVtt += lines[li] + '\n';
        if (translated[li]) newVtt += translated[li] + '\n';
      }
      vtt = newVtt;
    }

    return { vttText: vtt, allText, wordTimings };
  }

  // 前台转录前40分钟
  const fg = await transcribeRange(0, fgSegCount);

  if (!fg.allText) {
    try { fs.rmSync(tmpDir, { recursive: true }); } catch(e) {}
    sendSubtitleStatus('语音识别失败');
    return null;
  }

  // 先写入前台部分
  let fullVtt = 'WEBVTT\n\n' + fg.vttText;
  fs.writeFileSync(vttPath, fullVtt, 'utf-8');
  const wtsPath = vttPath.replace(/\.vtt$/, '.wordts.json');
  let allWordTimings = fg.wordTimings || [];
  fs.writeFileSync(wtsPath, JSON.stringify(allWordTimings), 'utf-8');

  if (fgSegCount < segCount) {
    sendSubtitleStatus(`前 ${Math.ceil(FOREGROUND_LIMIT/60)} 分钟字幕已就绪，剩余部分后台转录中...`);
    // 后台继续转录剩余部分
    (async () => {
      const bg = await transcribeRange(fgSegCount, segCount);
      if (bg.vttText) {
        fullVtt += bg.vttText;
        fs.writeFileSync(vttPath, fullVtt, 'utf-8');
        allWordTimings = allWordTimings.concat(bg.wordTimings || []);
        fs.writeFileSync(wtsPath, JSON.stringify(allWordTimings), 'utf-8');
      }
      try { fs.rmSync(tmpDir, { recursive: true }); } catch(e) {}
      sendSubtitleStatus(`全部转录完成，共 ${segCount} 段`);
      // 通知前端刷新字幕
      if (mainWindow && !mainWindow.isDestroyed()) {
        mainWindow.webContents.send('subtitle-updated', vttPath);
      }
    })();
  } else {
    try { fs.rmSync(tmpDir, { recursive: true }); } catch(e) {}
    sendSubtitleStatus(`转录完成，共 ${segCount} 段`);
  }

  return vttPath;
});

function fmtVTT(sec) {
  const h = Math.floor(sec / 3600), m = Math.floor((sec % 3600) / 60), s = sec % 60;
  return String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ':' + s.toFixed(3).padStart(6,'0');
}

