)

package com.multilanglearner.data.db.dao

import androidx.room.*
import com.multilanglearner.data.db.entity.FavoriteWord
import kotlinx.coroutines.flow.Flow

@Dao
interface FavoriteDao {
    @Query("SELECT * FROM favorites ORDER BY created_at DESC")
    fun getAll(): Flow<List<FavoriteWord>>

    @Query("SELECT * FROM favorites WHERE lang = :lang ORDER BY created_at DESC")
    fun getByLang(lang: String): Flow<List<FavoriteWord>>

    @Query("SELECT EXISTS(SELECT 1 FROM favorites WHERE word = :word AND lang = :lang)")
    suspend fun isFavorite(word: String, lang: String): Boolean

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(word: FavoriteWord)

    @Query("DELETE FROM favorites WHERE word = :word AND lang = :lang")
