import com.multilanglearner.domain.model.BAIDU_LANG_MAP
import kotlinx.serialization.json.*
import okhttp3.*
import okhttp3.HttpUrl.Companion.toHttpUrl
import java.security.MessageDigest
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

/**
 * Baidu Translate API - ported from main.js baiduTranslate()
 */
@Singleton
class TranslateService @Inject constructor() {
    private val client = OkHttpClient.Builder()
        .connectTimeout(10, TimeUnit.SECONDS)
        .readTimeout(10, TimeUnit.SECONDS)
        .build()

    private val json = Json { ignoreUnknownKeys = true }

    suspend fun baiduTranslate(
        text: String,
        fromLang: String,
        appId: String,
        appKey: String
    ): String? {
        if (appId.isBlank() || appKey.isBlank()) return null
        val salt = (10000..99999).random().toString()
        val sign = md5("$appId$text$salt$appKey")
        val baiduLang = BAIDU_LANG_MAP[fromLang] ?: "auto"

        val url = "https://fanyi-api.baidu.com/api/trans/vip/translate".toHttpUrl().newBuilder()
            .addQueryParameter("q", text)
            .addQueryParameter("from", baiduLang)
            .addQueryParameter("to", "zh")
            .addQueryParameter("appid", appId)
            .addQueryParameter("salt", salt)
            .addQueryParameter("sign", sign)
            .build()

        return try {
            val response = client.newCall(Request.Builder().url(url).build()).execute()
            val body = response.body?.string() ?: return null
            val jsonObj = json.parseToJsonElement(body).jsonObject
            jsonObj["trans_result"]?.jsonArray?.joinToString("\n") {
                it.jsonObject["dst"]?.jsonPrimitive?.contentOrNull ?: ""
            }
        } catch (e: Exception) { null }
    }

    private fun md5(input: String): String {
        val md = MessageDigest.getInstance("MD5")
        val digest = md.digest(input.toByteArray())
        return digest.joinToString("") { "%02x".format(it) }
    }
}

