package com.multilanglearner.domain.util

import com.multilanglearner.domain.model.SubtitleCue

/**
 * VTT subtitle parser - ported from renderer.js parseVTT()
 * Handles YouTube auto-generated subtitle quirks:
 * - Skips ultra-short entries (<50ms, transition frames)
 * - Takes last non-empty text line (YouTube dual-line format)
 * - Merges consecutive identical text entries
 */
object VttParser {
    private val TIMESTAMP_REGEX = Regex(
        """(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})"""
    )

    fun parse(vttContent: String): List<SubtitleCue> {
        val raw = mutableListOf<SubtitleCue>()
        val blocks = vttContent.replace("\r\n", "\n").split(Regex("\n\n+"))
        var index = 0

        for (block in blocks) {
            val lines = block.trim().split("\n")
            for (i in lines.indices) {
                val match = TIMESTAMP_REGEX.find(lines[i]) ?: continue
                val startMs = parseTimestamp(match, 1)
                val endMs = parseTimestamp(match, 5)
                // Skip ultra-short entries (YouTube transition frames)
                if (endMs - startMs < 50) break
                // Take last non-empty text line (YouTube dual-line: new content is last)
                val textLines = lines.drop(i + 1)
                    .map { it.replace(Regex("<[^>]+>"), "").trim() }
                    .filter { it.isNotEmpty() }
                val text = textLines.lastOrNull() ?: ""
                if (text.isNotEmpty()) {
                    raw.add(SubtitleCue(index++, startMs, endMs, text))
                }
                break
            }
        }

        // Merge consecutive identical text (dedup)
        val result = mutableListOf<SubtitleCue>()
        for (cue in raw) {
            if (result.isNotEmpty() && result.last().text == cue.text) {
                val last = result.last()
                result[result.lastIndex] = last.copy(endMs = cue.endMs)
            } else {
                result.add(cue)
            }
        }
        return result
    }

    private fun parseTimestamp(match: MatchResult, startGroup: Int): Long {
        val h = match.groupValues[startGroup].toLong()
        val m = match.groupValues[startGroup + 1].toLong()
        val s = match.groupValues[startGroup + 2].toLong()
        val ms = match.groupValues[startGroup + 3].toLong()
        return h * 3600000 + m * 60000 + s * 1000 + ms
    }

    /** Format seconds to VTT timestamp HH:MM:SS.mmm */
    fun formatVtt(sec: Double): String {
        val h = (sec / 3600).toInt()
        val m = ((sec % 3600) / 60).toInt()
        val s = sec % 60
        return "%02d:%02d:%06.3f".format(h, m, s)
    }
}

