122→    fun updatePosition(positionMs: Long) {
123→        _uiState.update { it.copy(currentPositionMs = positionMs) }
124→        val subs = _uiState.value.subtitles
125→        if (subs.isEmpty()) return
126→
127→        // Binary search for current cue (ported from renderer.js)
128→        var lo = 0; var hi = subs.size - 1; var idx = -1
129→        while (lo <= hi) {
130→            val mid = (lo + hi) ushr 1
131→            when {
132→                positionMs < subs[mid].startMs -> hi = mid - 1
133→                positionMs > subs[mid].endMs -> lo = mid + 1
134→                else -> { idx = mid; break }
135→            }
136→        }
137→        // Gap handling: find next cue within 0.5s
138→        if (idx < 0) {
139→            for (i in subs.indices) {
140→                if (subs[i].startMs > positionMs) {
141→                    idx = if (subs[i].startMs - positionMs < 500) i else if (i > 0) i - 1 else 0
142→                    break
