 35→@OptIn(ExperimentalMaterial3Api::class)
 36→@Composable
 37→fun PlayerScreen(
 38→    videoPath: String,
 39→    subtitlePath: String?,
 40→    onBack: () -> Unit,
 41→    viewModel: PlayerViewModel = hiltViewModel()
 42→) {
 43→    val uiState by viewModel.uiState.collectAsState()
 44→    val context = LocalContext.current
 45→    val listState = rememberLazyListState()
 46→
 47→    // ExoPlayer
 48→    val exoPlayer = remember {
 49→        ExoPlayer.Builder(context).build().apply {
 50→            setMediaItem(MediaItem.fromUri(videoPath))
 51→            prepare()
 52→        }
 53→    }
 54→
 55→    // Load subtitles
 56→    LaunchedEffect(videoPath) {
 57→        viewModel.loadSubtitles(videoPath, subtitlePath)
 58→    }
 59→
 60→    // 30ms position polling (ported from renderer.js syncTimer)
 61→    LaunchedEffect(exoPlayer) {
 62→        while (isActive) {
 63→            if (exoPlayer.isPlaying) {
 64→                viewModel.updatePosition(exoPlayer.currentPosition)
 65→            }
 66→            delay(30)
 67→        }
 68→    }
 69→
 70→    // Auto-scroll subtitle list
 71→    LaunchedEffect(uiState.currentCueIndex) {
 72→        if (uiState.currentCueIndex >= 0) {
 73→            listState.animateScrollToItem(uiState.currentCueIndex)
 74→        }
 75→    }
 76→
 77→    DisposableEffect(Unit) {
 78→        onDispose { exoPlayer.release() }
 79→    }
 80→
 81→    Scaffold(
 82→        topBar = {
 83→            TopAppBar(
 84→                title = { Text("视频学习") },
 85→                navigationIcon = {
 86→                    IconButton(onClick = { exoPlayer.release(); onBack() }) {
 87→                        Icon(Icons.Default.ArrowBack, "返回")
 88→                    }
 89→                }
 90→            )
 91→        }
 92→    ) { padding ->
 93→        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
 94→            // Video Player
 95→            AndroidView(
 96→                factory = {
 97→                    PlayerView(context).apply {
 98→                        player = exoPlayer
 99→                        layoutParams = FrameLayout.LayoutParams(
100→                            ViewGroup.LayoutParams.MATCH_PARENT,
101→                            ViewGroup.LayoutParams.WRAP_CONTENT
102→                        )
103→                    }
104→                },
105→                modifier = Modifier.fillMaxWidth().heightIn(max = 300.dp)
106→            )
107→
108→            // Mode bar (学习/听写/重新转录)
109→            Row(
110→                modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
111→                horizontalArrangement = Arrangement.spacedBy(8.dp)
112→            ) {
113→                FilterChip(
114→                    selected = uiState.mode == "learn",
115→                    onClick = { viewModel.setMode("learn") },
116→                    label = { Text("学习模式") }
117→                )
118→                FilterChip(
119→                    selected = uiState.mode == "dictation",
120→                    onClick = { viewModel.setMode("dictation") },
121→                    label = { Text("听写模式") }
122→                )
123→                Spacer(Modifier.weight(1f))
124→                AssistChip(
125→                    onClick = { exoPlayer.pause(); viewModel.retranscribe(videoPath) },
126→                    enabled = !uiState.isTranscribing,
127→                    label = { Text(if (uiState.isTranscribing) "转录中..." else "🔄 重新转录") }
128→                )
129→            }
130→
131→            if (uiState.mode == "learn") {
132→                // === Learning Mode ===
