package com.multilanglearner.ui.player

import android.view.ViewGroup
import android.widget.FrameLayout
import androidx.compose.animation.AnimatedVisibility
import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.itemsIndexed
import androidx.compose.foundation.lazy.rememberLazyListState
import androidx.compose.foundation.text.BasicTextField
import androidx.compose.foundation.text.ClickableText
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.*
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.compose.ui.viewinterop.AndroidView
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.media3.common.MediaItem
import androidx.media3.exoplayer.ExoPlayer
import androidx.media3.ui.PlayerView
import kotlinx.coroutines.delay
import kotlinx.coroutines.isActive

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun PlayerScreen(
    videoPath: String,
    subtitlePath: String?,
    onBack: () -> Unit,
    viewModel: PlayerViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()
    val context = LocalContext.current
    val listState = rememberLazyListState()

    // ExoPlayer
    val exoPlayer = remember {
        ExoPlayer.Builder(context).build().apply {
            setMediaItem(MediaItem.fromUri(videoPath))
            prepare()
        }
    }

    // Load subtitles
    LaunchedEffect(videoPath) {
        viewModel.loadSubtitles(videoPath, subtitlePath)
    }

    // 30ms position polling (ported from renderer.js syncTimer)
    LaunchedEffect(exoPlayer) {
        while (isActive) {
            if (exoPlayer.isPlaying) {
                viewModel.updatePosition(exoPlayer.currentPosition)
            }
            delay(30)
        }
    }

    // Auto-scroll subtitle list
    LaunchedEffect(uiState.currentCueIndex) {
        if (uiState.currentCueIndex >= 0) {
            listState.animateScrollToItem(uiState.currentCueIndex)
        }
    }

    DisposableEffect(Unit) {
        onDispose { exoPlayer.release() }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("视频学习") },
                navigationIcon = {
                    IconButton(onClick = { exoPlayer.release(); onBack() }) {
                        Icon(Icons.Default.ArrowBack, "返回")
                    }
                }
            )
        }
    ) { padding ->
        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
            // Video Player
            AndroidView(
                factory = {
                    PlayerView(context).apply {
                        player = exoPlayer
                        layoutParams = FrameLayout.LayoutParams(
                            ViewGroup.LayoutParams.MATCH_PARENT,
                            ViewGroup.LayoutParams.WRAP_CONTENT
                        )
                    }
                },
                modifier = Modifier.fillMaxWidth().heightIn(max = 300.dp)
            )

            // Mode bar (学习/听写/重新转录)
            Row(
                modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                FilterChip(
                    selected = uiState.mode == "learn",
                    onClick = { viewModel.setMode("learn") },
                    label = { Text("学习模式") }
                )
                FilterChip(
                    selected = uiState.mode == "dictation",
                    onClick = { viewModel.setMode("dictation") },
                    label = { Text("听写模式") }
                )
                Spacer(Modifier.weight(1f))
                AssistChip(
                    onClick = { exoPlayer.pause(); viewModel.retranscribe(videoPath) },
                    enabled = !uiState.isTranscribing,
                    label = { Text(if (uiState.isTranscribing) "转录中..." else "🔄 重新转录") }
                )
            }

            if (uiState.mode == "learn") {
                // === Learning Mode ===
                // Current subtitle with karaoke highlighting
                Card(
                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        if (uiState.currentCueIndex >= 0 && uiState.currentCueIndex < uiState.subtitles.size) {
                            val cue = uiState.subtitles[uiState.currentCueIndex]
                            val words = cue.text.split(Regex("\\s+")).filter { it.isNotBlank() }
                            val timings = viewModel.getAlignedTimings(words)
                            val currentSec = uiState.currentPositionMs / 1000.0

                            // Karaoke-style word-by-word display - clickable for instant lookup
                            val annotatedText = buildAnnotatedString {
                                words.forEachIndexed { i, word ->
                                    val wt = timings.getOrNull(i)
                                    val style = when {
                                        wt != null && currentSec >= wt.s && currentSec < wt.e ->
                                            SpanStyle(color = MaterialTheme.colorScheme.primary, fontWeight = FontWeight.Bold, fontSize = 24.sp)
                                        wt != null && currentSec >= wt.e ->
                                            SpanStyle(color = MaterialTheme.colorScheme.primary.copy(alpha = 0.7f), fontSize = 22.sp)
                                        else -> SpanStyle(color = MaterialTheme.colorScheme.onSurface, fontSize = 22.sp)
                                    }
                                    pushStringAnnotation("word", word.replace(Regex("[^\\p{L}\\p{M}'-]"), ""))
                                    withStyle(style) { append(word) }
                                    pop()
                                    if (i < words.size - 1) append(" ")
                                }
                            }
                            ClickableText(
                                text = annotatedText,
                                modifier = Modifier.fillMaxWidth(),
                                style = TextStyle(textAlign = TextAlign.Center),
                                onClick = { offset ->
                                    annotatedText.getStringAnnotations("word", offset, offset)
                                        .firstOrNull()?.let { annotation ->
                                            val cleanWord = annotation.item
                                            if (cleanWord.isNotBlank()) {
                                                viewModel.lookupWord(cleanWord)
                                            }
                                        }
                                }
                            )

                            // Translation line (if bilingual)
                            cue.translation?.let { trans ->
                                Spacer(Modifier.height(4.dp))
                                Text(trans, color = MaterialTheme.colorScheme.onSurfaceVariant,
                                    style = MaterialTheme.typography.bodyMedium)
                            }
                        } else {
                            Text(uiState.statusText, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }

                        // AI analyze button
                        if (uiState.currentSentence.isNotBlank()) {
                            Spacer(Modifier.height(8.dp))
                            Row {
                                TextButton(onClick = { viewModel.analyzeSentence() }) {
                                    Icon(Icons.Default.Psychology, null, Modifier.size(16.dp))
                                    Spacer(Modifier.width(4.dp))
                                    Text("AI分析此句")
                                }
                            }
                        }
                    }
                }

                // Word card panel
                AnimatedVisibility(visible = uiState.showWordCard && uiState.wordCardData != null) {
                    uiState.wordCardData?.let { card ->
                        WordCardPanel(
                            card = card,
                            onSpeak = { viewModel.speak(card.word) },
                            onFavorite = { viewModel.toggleFavorite(card.word, card.phonetic, card.translation) },
                            onDismiss = { viewModel.hideWordCard() }
                        )
                    }
                }

                // AI analysis result
                uiState.aiAnalysisResult?.let { result ->
                    Card(
                        modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.primaryContainer)
                    ) {
                        Text(result, modifier = Modifier.padding(12.dp),
                            style = MaterialTheme.typography.bodyMedium)
                    }
                }

                // Subtitle scroll list
                LazyColumn(
                    state = listState,
                    modifier = Modifier.fillMaxWidth().weight(1f).padding(horizontal = 16.dp),
                    verticalArrangement = Arrangement.spacedBy(2.dp)
                ) {
                    itemsIndexed(uiState.subtitles) { index, cue ->
                        val isActive = index == uiState.currentCueIndex
                        Surface(
                            modifier = Modifier.fillMaxWidth()
                                .clickable { exoPlayer.seekTo(cue.startMs); exoPlayer.play() },
                            color = if (isActive) MaterialTheme.colorScheme.primaryContainer
                                    else Color.Transparent,
                            shape = MaterialTheme.shapes.small
                        ) {
                            Row(modifier = Modifier.padding(8.dp), verticalAlignment = Alignment.CenterVertically) {
                                Text(
                                    formatTime(cue.startMs),
                                    color = MaterialTheme.colorScheme.primary,
                                    style = MaterialTheme.typography.labelSmall,
                                    modifier = Modifier.width(48.dp)
                                )
                                Text(
                                    cue.text,
                                    style = MaterialTheme.typography.bodyMedium,
                                    fontWeight = if (isActive) FontWeight.Bold else FontWeight.Normal
                                )
                            }
                        }
                    }
                }

            } else {
                // === Dictation Mode ===
                DictationPanel(
                    subtitle = uiState.subtitles.getOrNull(uiState.dictationIndex),
                    onSpeak = { text -> viewModel.speak(text) },
                    onNext = { viewModel.nextDictation() },
                    onLookup = { word -> viewModel.lookupWord(word) }
                )
            }
        }
    }
}

@Composable
fun WordCardPanel(
    card: WordCardData,
    onSpeak: () -> Unit,
    onFavorite: () -> Unit,
    onDismiss: () -> Unit
) {
    Card(
        modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface)
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text(card.word, style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.Bold)
                if (card.phonetic.isNotBlank()) {
                    Spacer(Modifier.width(8.dp))
                    Text(card.phonetic, color = MaterialTheme.colorScheme.onSurfaceVariant, style = MaterialTheme.typography.bodySmall)
                }
                Spacer(Modifier.weight(1f))
                IconButton(onClick = onSpeak) { Icon(Icons.Default.VolumeUp, "发音") }
                IconButton(onClick = onFavorite) { Icon(Icons.Default.Favorite, "收藏") }
                IconButton(onClick = onDismiss) { Icon(Icons.Default.Close, "关闭") }
            }
            Text(card.translation, style = MaterialTheme.typography.bodyLarge, color = MaterialTheme.colorScheme.primary)
            if (card.definitions.isNotEmpty()) {
                Spacer(Modifier.height(8.dp))
                Text("📖 释义", style = MaterialTheme.typography.labelMedium)
                card.definitions.forEach { def ->
                    Text("${def.partOfSpeech} ${def.definition}", style = MaterialTheme.typography.bodySmall)
                }
            }
            if (card.examples.isNotEmpty()) {
                Spacer(Modifier.height(8.dp))
                Text("💬 例句", style = MaterialTheme.typography.labelMedium)
                card.examples.forEach { ex ->
                    Text(ex, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            }
        }
    }
}

@Composable
fun DictationPanel(
    subtitle: SubtitleCue?,
    onSpeak: (String) -> Unit,
    onNext: () -> Unit,
    onLookup: (String) -> Unit
) {
    if (subtitle == null) {
        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
        }
        return
    }

    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        // Word input boxes
        Card(modifier = Modifier.fillMaxWidth()) {
            Column(modifier = Modifier.padding(16.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    words.forEachIndexed { i, word ->
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            OutlinedTextField(
                                value = inputs[i],
                                onValueChange = { inputs[i] = it },
                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
                                singleLine = true,
                                isError = results[i] == "wrong",
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
                                )
                            )
                            if (results[i] == "wrong") {
                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
                            }
                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
                                Text("查词", style = MaterialTheme.typography.labelSmall)
                            }
                        }
                    }
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        // Control buttons
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            Button(onClick = { onSpeak(subtitle.text) }) {
                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
                Spacer(Modifier.width(4.dp))
                Text("朗读")
            }
            Button(onClick = {
                answers.forEachIndexed { i, answer ->
                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
                }
            }) {
                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
                Spacer(Modifier.width(4.dp))
                Text("检查")
            }
            Button(onClick = {
                inputs.indices.forEach { inputs[it] = "" }
                results.indices.forEach { results[it] = "" }
                onNext()
            }) {
                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
                Spacer(Modifier.width(4.dp))
                Text("下一句")
            }
        }
    }
}

private fun formatTime(ms: Long): String {
    val totalSec = ms / 1000
    val m = totalSec / 60
    val s = totalSec % 60
    return "$m:${s.toString().padStart(2, '0')}"
}

