package com.multilanglearner.domain.util

/**
 * Text segmenter for TTS - ported from renderer.js speakLecture()
 * Splits text into chunks ≤200 chars, preferring sentence boundaries.
 */
object TextSegmenter {
    fun segment(text: String, maxLength: Int = 200): List<String> {
        val chunks = mutableListOf<String>()
        var remaining = text
        while (remaining.isNotEmpty()) {
            if (remaining.length <= maxLength) {
                chunks.add(remaining)
                break
            }
            var cut = remaining.lastIndexOf('。', maxLength)
            if (cut < 50) cut = remaining.lastIndexOf('.', maxLength)
            if (cut < 50) cut = remaining.lastIndexOf('，', maxLength)
            if (cut < 50) cut = maxLength
            chunks.add(remaining.substring(0, cut + 1))
            remaining = remaining.substring(cut + 1)
        }
        return chunks
    }
}

