package com.multilanglearner.ui.vocabulary

import android.graphics.*
import android.graphics.Paint
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.grid.GridCells
import androidx.compose.foundation.lazy.grid.LazyVerticalGrid
import androidx.compose.foundation.lazy.grid.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.multilanglearner.data.db.entity.FavoriteWord

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun VocabularyScreen(
    onBack: () -> Unit,
    viewModel: VocabularyViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()
    val selectedIds = remember { mutableStateListOf<Long>() }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("📖 我的词书") },
                navigationIcon = {
                    IconButton(onClick = onBack) { Icon(Icons.Default.ArrowBack, "返回") }
                },
                actions = {
                    TextButton(onClick = { viewModel.importFromClipboard() }) { Text("📋 导入") }
                    TextButton(onClick = {
                        if (selectedIds.size == uiState.words.size) selectedIds.clear()
                        else { selectedIds.clear(); selectedIds.addAll(uiState.words.map { it.id }) }
                    }) { Text("☑ 全选") }
                    TextButton(
                        onClick = { viewModel.generateImage(uiState.words.filter { it.id in selectedIds }) },
                        enabled = selectedIds.isNotEmpty()
                    ) { Text("🖼 成图(${selectedIds.size})") }
                    TextButton(onClick = { viewModel.aiClassifyAndImage() }) { Text("🤖 AI分类") }
                }
            )
        }
    ) { padding ->
        if (uiState.words.isEmpty()) {
            Box(Modifier.fillMaxSize().padding(padding), contentAlignment = Alignment.Center) {
                Text("词书为空，点击字幕单词旁的☆收藏", color = MaterialTheme.colorScheme.onSurfaceVariant)
            }
        } else {
            LazyVerticalGrid(
                columns = GridCells.Adaptive(160.dp),
                modifier = Modifier.fillMaxSize().padding(padding).padding(8.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(uiState.words, key = { it.id }) { word ->
                    val isSelected = word.id in selectedIds
                    Card(
                        onClick = {
                            if (isSelected) selectedIds.remove(word.id) else selectedIds.add(word.id)
                        },
                        colors = CardDefaults.cardColors(
                            containerColor = if (isSelected) MaterialTheme.colorScheme.primaryContainer
                            else MaterialTheme.colorScheme.surface
                        )
                    ) {
                        Column(modifier = Modifier.padding(12.dp)) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Checkbox(checked = isSelected, onCheckedChange = {
                                    if (it) selectedIds.add(word.id) else selectedIds.remove(word.id)
                                })
                                Text(word.word, style = MaterialTheme.typography.titleSmall,
                                    color = MaterialTheme.colorScheme.primary)
                                Spacer(Modifier.weight(1f))
                                IconButton(onClick = { viewModel.deleteWord(word) }, modifier = Modifier.size(24.dp)) {
                                    Icon(Icons.Default.Close, "删除", Modifier.size(16.dp))
                                }
                            }
                            if (word.phonetic.isNotBlank()) {
                                Text(word.phonetic, style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant)
                            }
                            Text(word.translation.ifBlank { "" }, style = MaterialTheme.typography.bodySmall)
                        }
                    }
                }
            }
        }

        // Image generation result dialog
        uiState.generatedImageBitmap?.let { bitmap ->
            AlertDialog(
                onDismissRequest = { viewModel.clearImage() },
                title = { Text("🖼 词汇图片") },
                text = {
                    // In real implementation, display the bitmap
                    Text("图片已生成 (${bitmap.width}x${bitmap.height})")
                },
                confirmButton = {
                    TextButton(onClick = { viewModel.saveImage(bitmap); viewModel.clearImage() }) { Text("💾 保存") }
                },
                dismissButton = {
                    TextButton(onClick = { viewModel.clearImage() }) { Text("关闭") }
                }
            )
        }
    }
}

