package com.multilanglearner.ui.regulation

import android.speech.tts.TextToSpeech
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.LazyRow
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.multilanglearner.domain.model.RegulationCountry
import com.multilanglearner.domain.model.RegulationItem
import java.util.Locale

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun RegulationScreen(
    onBack: () -> Unit,
    viewModel: RegulationViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()
    val context = LocalContext.current
    var tts by remember { mutableStateOf<TextToSpeech?>(null) }
    var showAddCountry by remember { mutableStateOf(false) }
    var showAddItem by remember { mutableStateOf(false) }

    LaunchedEffect(Unit) {
        tts = TextToSpeech(context) { }
        viewModel.loadRegulations()
    }

    DisposableEffect(Unit) { onDispose { tts?.shutdown() } }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("⚖ 跨国法规库") },
                navigationIcon = { IconButton(onClick = onBack) { Icon(Icons.Default.ArrowBack, "返回") } }
            )
        }
    ) { padding ->
        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
            // Country tabs
            LazyRow(
                modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(uiState.countries) { country ->
                    FilterChip(
                        selected = country.code == uiState.selectedCountry,
                        onClick = { viewModel.selectCountry(country.code) },
                        label = { Text(country.name) }
                    )
                }
                item {
                    AssistChip(
                        onClick = { showAddCountry = true },
                        label = { Text("＋ 添加") }
                    )
                }
            }

            // Law items
            val selectedCountry = uiState.countries.find { it.code == uiState.selectedCountry }
            if (selectedCountry != null) {
                LazyColumn(
                    modifier = Modifier.fillMaxSize().padding(horizontal = 16.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    items(selectedCountry.items) { item ->
                        Card(modifier = Modifier.fillMaxWidth()) {
                            Column(modifier = Modifier.padding(16.dp)) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Text(item.title, style = MaterialTheme.typography.titleSmall, modifier = Modifier.weight(1f))
                                    IconButton(onClick = {
                                        tts?.language = Locale.forLanguageTag(selectedCountry.lang)
                                        tts?.setSpeechRate(0.85f)
                                        tts?.speak(item.content, TextToSpeech.QUEUE_FLUSH, null, "law_tts")
                                    }) { Icon(Icons.Default.VolumeUp, "朗读") }
                                    if (item.isUser) {
                                        IconButton(onClick = { viewModel.deleteItem(item.id) }) {
                                            Icon(Icons.Default.Delete, "删除", tint = MaterialTheme.colorScheme.error)
                                        }
                                    }
                                }
                                Text(item.content, style = MaterialTheme.typography.bodyMedium)
                            }
                        }
                    }
                    item {
                        OutlinedCard(
                            onClick = { showAddItem = true },
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Box(Modifier.fillMaxWidth().padding(16.dp), contentAlignment = Alignment.Center) {
                                Text("＋ 添加法规条目", color = MaterialTheme.colorScheme.onSurfaceVariant)
                            }
                        }
                    }
                }
            }
        }

        // Add country dialog
        if (showAddCountry) {
            var code by remember { mutableStateOf("") }
            var name by remember { mutableStateOf("") }
            AlertDialog(
                onDismissRequest = { showAddCountry = false },
                title = { Text("添加新国家/地区") },
                text = {
                    Column {
                        OutlinedTextField(value = code, onValueChange = { code = it }, label = { Text("代码 (如 sg)") }, singleLine = true)
                        Spacer(Modifier.height(8.dp))
                        OutlinedTextField(value = name, onValueChange = { name = it }, label = { Text("名称 (如 新加坡)") }, singleLine = true)
                    }
                },
                confirmButton = {
                    TextButton(onClick = {
                        if (code.isNotBlank() && name.isNotBlank()) {
                            viewModel.addCountry(code.lowercase(), name)
                            showAddCountry = false
                        }
                    }) { Text("保存") }
                },
                dismissButton = { TextButton(onClick = { showAddCountry = false }) { Text("取消") } }
            )
        }

        // Add item dialog
        if (showAddItem) {
            var title by remember { mutableStateOf("") }
            var content by remember { mutableStateOf("") }
            AlertDialog(
                onDismissRequest = { showAddItem = false },
                title = { Text("添加法规条目") },
                text = {
                    Column {
                        OutlinedTextField(value = title, onValueChange = { title = it }, label = { Text("标题") }, singleLine = true)
                        Spacer(Modifier.height(8.dp))
                        OutlinedTextField(value = content, onValueChange = { content = it }, label = { Text("内容") }, minLines = 3)
                    }
                },
                confirmButton = {
                    TextButton(onClick = {
                        if (title.isNotBlank() && content.isNotBlank()) {
                            viewModel.addItem(title, content)
                            showAddItem = false
                        }
                    }) { Text("保存") }
                },
                dismissButton = { TextButton(onClick = { showAddItem = false }) { Text("取消") } }
            )
        }
    }
}

package com.multilanglearner.ui.ai

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.multilanglearner.domain.model.AI_PROVIDERS

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AISettingsSheet(
    onDismiss: () -> Unit,
    viewModel: AISettingsViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()

    ModalBottomSheet(onDismissRequest = onDismiss) {
        Column(modifier = Modifier.padding(16.dp).fillMaxWidth()) {
            Text("⚙ AI 设置", style = MaterialTheme.typography.titleLarge)
            Text("AI 用于词汇释义、句子分析等功能", style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant)

            Spacer(Modifier.height(12.dp))

            // Provider selector
            var providerExpanded by remember { mutableStateOf(false) }
            ExposedDropdownMenuBox(expanded = providerExpanded, onExpandedChange = { providerExpanded = it }) {
                OutlinedTextField(
                    value = AI_PROVIDERS.find { it.id == uiState.provider }?.name ?: "",
                    onValueChange = {},
                    readOnly = true,
                    label = { Text("AI 服务商") },
                    modifier = Modifier.fillMaxWidth().menuAnchor(),
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(providerExpanded) }
                )
                ExposedDropdownMenu(expanded = providerExpanded, onDismissRequest = { providerExpanded = false }) {
                    AI_PROVIDERS.forEach { provider ->
                        DropdownMenuItem(
                            text = { Text(provider.name) },
                            onClick = { viewModel.setProvider(provider.id); providerExpanded = false }
                        )
                    }
                }
            }

            Spacer(Modifier.height(8.dp))
            OutlinedTextField(value = uiState.apiKey, onValueChange = viewModel::setApiKey,
                label = { Text("API Key") }, modifier = Modifier.fillMaxWidth(), singleLine = true)

            Spacer(Modifier.height(8.dp))
            OutlinedTextField(value = uiState.baseUrl, onValueChange = viewModel::setBaseUrl,
                label = { Text("Base URL (可选)") }, modifier = Modifier.fillMaxWidth(), singleLine = true)

            Spacer(Modifier.height(8.dp))
            OutlinedTextField(value = uiState.model, onValueChange = viewModel::setModel,
                label = { Text("模型名称 (可选)") }, modifier = Modifier.fillMaxWidth(), singleLine = true)

            Spacer(Modifier.height(8.dp))
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
