const { app, BrowserWindow, ipcMain, dialog } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const fs = require('fs');
const https = require('https');
const http = require('http');
const crypto = require('crypto');

// 百度翻译API配置
const TRANSLATE_CONFIG_PATH = path.join(require('os').homedir(), '.clawdbot', 'translate_config.json');
const BAIDU_LANG_MAP = { en:'en', ja:'jp', ko:'kor', fr:'fra', de:'de', ru:'ru', es:'spa', pt:'pt', it:'it', ar:'ara', th:'th', vi:'vie', id:'id', ms:'may', hi:'hi' };

function loadTranslateConfig() {
  try { return JSON.parse(fs.readFileSync(TRANSLATE_CONFIG_PATH, 'utf-8')); } catch(e) { return {}; }
}

function baiduTranslate(text, fromLang) {
  return new Promise((resolve) => {
    const cfg = loadTranslateConfig();
    const appid = cfg.baidu_appid || '', key = cfg.baidu_key || '';
    if (!appid || !key) { resolve(null); return; }
    const salt = String(Math.floor(Math.random() * 90000) + 10000);
    const sign = crypto.createHash('md5').update(appid + text + salt + key).digest('hex');
    const params = new URLSearchParams({ q: text, from: BAIDU_LANG_MAP[fromLang] || 'auto', to: 'zh', appid, salt, sign });
    https.get('https://fanyi-api.baidu.com/api/trans/vip/translate?' + params, (res) => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => {
        try {
          const json = JSON.parse(d);
          if (json.trans_result) resolve(json.trans_result.map(r => r.dst).join('\n'));
          else resolve(null);
        } catch(e) { resolve(null); }
      });
    }).on('error', () => resolve(null));
  });
}

let mainWindow;
let db = null;
let userDb = null;
let currentLangGlobal = 'en';

const BIN_DIR = app.isPackaged
  ? path.join(process.resourcesPath, 'bin')
  : path.join('E:', '视频下载器具', 'bin');
const YTDLP = path.join(BIN_DIR, 'yt-dlp.exe');
const FFMPEG_DIR = BIN_DIR;
const USER_DATA = app.isPackaged ? path.join(app.getPath('userData')) : __dirname;
const DOWNLOADS = path.join(USER_DATA, 'downloads');
const AI_CONFIG_FILE = path.join(USER_DATA, 'ai_config.json');

// 6家AI预设 + 自定义
const AI_PROVIDERS = {
  openai:   { name: 'OpenAI',        baseUrl: 'https://api.openai.com/v1',              model: 'gpt-4o-mini' },
  claude:   { name: 'Claude',        baseUrl: 'https://api.anthropic.com/v1',           model: 'claude-sonnet-4-20250514' },
  groq:     { name: 'Groq',          baseUrl: 'https://api.groq.com/openai/v1',         model: 'llama-3.3-70b-versatile' },
  deepseek: { name: 'DeepSeek(深度求索)', baseUrl: 'https://api.deepseek.com/v1',            model: 'deepseek-chat' },
  qwen:     { name: 'Qwen(通义千问)',    baseUrl: 'https://dashscope.aliyuncs.com/compatible-mode/v1', model: 'qwen-plus' },
  zhipu:    { name: 'Zhipu(智谱清言)',   baseUrl: 'https://open.bigmodel.cn/api/paas/v4',  model: 'glm-4-flash' },
  custom:   { name: '自定义(OpenAI兼容)', baseUrl: '',                                       model: '' }
};

function loadAIConfig() {
  try {
    if (fs.existsSync(AI_CONFIG_FILE)) return JSON.parse(fs.readFileSync(AI_CONFIG_FILE, 'utf-8'));
  } catch(e) {}
  // 从环境变量读取
  const envKey = process.env.ANTHROPIC_AUTH_TOKEN || process.env.OPENAI_API_KEY || '';
  const envBase = process.env.ANTHROPIC_BASE_URL || '';
  const envModel = process.env.ANTHROPIC_DEFAULT_MODEL || '';
  if (envKey) {
    return { provider: envBase ? 'custom' : 'claude', apiKey: envKey, baseUrl: envBase, model: envModel };
  }
  return { provider: 'deepseek', apiKey: '', baseUrl: '', model: '' };
}
function saveAIConfig(cfg) { fs.writeFileSync(AI_CONFIG_FILE, JSON.stringify(cfg, null, 2)); }

// 通用AI调用 (OpenAI兼容格式, Claude单独处理)
function callAI(prompt) {
  return new Promise((resolve) => {
    const cfg = loadAIConfig();
    if (!cfg.apiKey) { resolve(null); return; }

    const preset = AI_PROVIDERS[cfg.provider] || {};
    const baseUrl = cfg.baseUrl || preset.baseUrl || '';
    const model = cfg.model || preset.model || '';
    const maxTokens = cfg.maxTokens || 1024;
    const temperature = cfg.temperature !== null && cfg.temperature !== undefined ? cfg.temperature : undefined;
    if (!baseUrl) { resolve(null); return; }

    const isClaude = cfg.provider === 'claude' || (model && model.toLowerCase().includes('claude'));
    const urlObj = new URL(isClaude ? baseUrl + '/messages' : baseUrl + '/chat/completions');
    const isHttps = urlObj.protocol === 'https:';

    let body, headers;
    if (isClaude) {
      const bodyObj = { model, max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] };
      if (temperature !== undefined) bodyObj.temperature = temperature;
      body = JSON.stringify(bodyObj);
      headers = {
        'Content-Type': 'application/json',
        'x-api-key': cfg.apiKey,
        'anthropic-version': '2023-06-01'
      };
    } else {
      const bodyObj = {
        model, max_tokens: maxTokens,
        messages: [
          { role: 'system', content: '你是多语言学习助手。用中文回答。翻译要准确，不要音译。简洁直接。' },
          { role: 'user', content: prompt }
        ]
      };
      if (temperature !== undefined) bodyObj.temperature = temperature;
      body = JSON.stringify(bodyObj);
      headers = {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + cfg.apiKey
      };
    }

    const opts = {
      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
      path: urlObj.pathname, method: 'POST', headers
    };

    const client = isHttps ? https : http;
    const req = client.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (isClaude) {
            resolve(json.content?.[0]?.text || null);
          } else {
            resolve(json.choices?.[0]?.message?.content || null);
          }
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(15000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });
}

const LANGUAGES = {
  en: { name: '英语', sub: 'en', tts: 'en-US' },
  ja: { name: '日语', sub: 'ja', tts: 'ja-JP' },
  ko: { name: '韩语', sub: 'ko', tts: 'ko-KR' },
  ru: { name: '俄语', sub: 'ru', tts: 'ru-RU' },
  th: { name: '泰语', sub: 'th', tts: 'th-TH' },
  vi: { name: '越南语', sub: 'vi', tts: 'vi-VN' },
  ms: { name: '马来语', sub: 'ms', tts: 'ms-MY' },
  id: { name: '印尼语', sub: 'id', tts: 'id-ID' },
  ar: { name: '阿拉伯语', sub: 'ar', tts: 'ar-SA' },
  pt: { name: '葡萄牙语', sub: 'pt', tts: 'pt-BR' },
  es: { name: '西班牙语', sub: 'es', tts: 'es-ES' },
  fr: { name: '法语', sub: 'fr', tts: 'fr-FR' },
  de: { name: '德语', sub: 'de', tts: 'de-DE' },
  hi: { name: '印地语', sub: 'hi', tts: 'hi-IN' }
};

function initDB() {
  const dbPath = path.join(__dirname, 'stardict.db');
  if (fs.existsSync(dbPath)) {
    try {
      const Database = require('better-sqlite3');
      db = new Database(dbPath, { readonly: true });
      db.pragma('journal_mode = WAL');
    } catch (e) { console.error('ECDICT加载失败:', e.message); }
  }
}

function initUserDB() {
  try {
    const Database = require('better-sqlite3');
    userDb = new Database(path.join(USER_DATA, 'userdata.db'));
    userDb.pragma('journal_mode = WAL');
    userDb.exec(`CREATE TABLE IF NOT EXISTS favorites (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      word TEXT NOT NULL, lang TEXT NOT NULL DEFAULT 'en',
      phonetic TEXT DEFAULT '', translation TEXT DEFAULT '',
      context TEXT DEFAULT '', created_at INTEGER NOT NULL,
      box TEXT DEFAULT ''
    )`);
    userDb.exec(`CREATE UNIQUE INDEX IF NOT EXISTS idx_fav_word_lang ON favorites(word, lang)`);
    // 兼容旧表：添加 box 列
    try { userDb.exec(`ALTER TABLE favorites ADD COLUMN box TEXT DEFAULT ''`); } catch(e) {}
    // 用户自定义法规表
    userDb.exec(`CREATE TABLE IF NOT EXISTS user_regulations (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      country_code TEXT NOT NULL, country_name TEXT NOT NULL,
      country_lang TEXT NOT NULL DEFAULT 'en-US',
      title TEXT NOT NULL, content TEXT NOT NULL
    )`);
  } catch (e) { console.error('UserDB初始化失败:', e.message); }
}

