function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1100, height: 850, minWidth: 900, minHeight: 700,
    backgroundColor: '#0a0a1a',
    webPreferences: { nodeIntegration: true, contextIsolation: false, webSecurity: false, zoomFactor: 1.0 }
  });
  mainWindow.loadFile('index.html');
  // 允许 Ctrl+滚轮缩放
  mainWindow.webContents.on('zoom-changed', (_, dir) => {
    const cur = mainWindow.webContents.getZoomLevel();
    mainWindow.webContents.setZoomLevel(cur + (dir === 'in' ? 0.5 : -0.5));
  });
}

