  const prompt = `解释${langName}词「${word}」${context ? '（语境:"'+context+'"）' : ''}。格式：
【释义】中文释义
【发音】国际音标
【例句】2个例句(附中文)
【助记】记忆技巧`;
  const result = await callAI(prompt);
  return result;
});

// AI智能分析字幕句子
ipcMain.handle('ai-analyze-sentence', async (_, sentence, lang) => {
  const langName = LANGUAGES[lang]?.name || lang;
  const prompt = `分析${langName}句子："${sentence}"
【翻译】中文翻译
【语法】1-2个关键语法点
【重点词汇】2-3个重要词汇及释义`;
  return await callAI(prompt);
});

// ===== 收藏夹 CRUD =====
ipcMain.handle('fav-add', (_, word, lang, phonetic, translation, context) => {
  if (!userDb) return false;
  try {
    userDb.prepare('INSERT OR REPLACE INTO favorites (word,lang,phonetic,translation,context,created_at) VALUES (?,?,?,?,?,?)').run(word, lang || 'en', phonetic || '', translation || '', context || '', Date.now());
    return true;
  } catch(e) { return false; }
});
ipcMain.handle('fav-remove', (_, word, lang) => {
  if (!userDb) return false;
  try { userDb.prepare('DELETE FROM favorites WHERE word=? AND lang=?').run(word, lang || 'en'); return true; } catch(e) { return false; }
});
ipcMain.handle('fav-check', (_, word, lang) => {
  if (!userDb) return false;
  try { return !!userDb.prepare('SELECT 1 FROM favorites WHERE word=? AND lang=?').get(word, lang || 'en'); } catch(e) { return false; }
});
ipcMain.handle('fav-list', (_, lang) => {
  if (!userDb) return [];
  try {
    if (lang) return userDb.prepare('SELECT * FROM favorites WHERE lang=? ORDER BY created_at DESC').all(lang);
    return userDb.prepare('SELECT * FROM favorites ORDER BY created_at DESC').all();
  } catch(e) { return []; }
});
ipcMain.handle('fav-import', (_, words, lang) => {
  if (!userDb) return 0;
  let count = 0;
  const stmt = userDb.prepare('INSERT OR IGNORE INTO favorites (word,lang,phonetic,translation,context,created_at) VALUES (?,?,\'\',\'\',\'\',?)');
  for (const w of words) { if (w.trim()) { stmt.run(w.trim(), lang || 'en', Date.now()); count++; } }
  return count;
});

// ===== 箱子/抽屉管理 =====
ipcMain.handle('fav-set-box', (_, wordId, box) => {
  if (!userDb) return false;
  try { userDb.prepare('UPDATE favorites SET box=? WHERE id=?').run(box || '', wordId); return true; } catch(e) { return false; }
});
ipcMain.handle('fav-list-boxes', () => {
  if (!userDb) return [];
  try { return userDb.prepare("SELECT DISTINCT box FROM favorites WHERE box!='' ORDER BY box").all().map(r => r.box); } catch(e) { return []; }
});
ipcMain.handle('fav-batch-set-box', (_, ids, box) => {
  if (!userDb) return false;
  try {
    const stmt = userDb.prepare('UPDATE favorites SET box=? WHERE id=?');
    for (const id of ids) stmt.run(box || '', id);
    return true;
  } catch(e) { return false; }
});

// ===== AI: 分组单词 =====
ipcMain.handle('ai-group-words', async (_, words) => {
  const prompt = `将以下单词按语义分组，每组给中文主题名：${words.join(', ')}
回复JSON：[{"group":"主题名","words":["word1","word2"]}]，只回复JSON。`;
  return await callAI(prompt);
});

// ===== AI: 场景描述 =====
ipcMain.handle('ai-scene-desc', async (_, group, words) => {
  const prompt = `为以下一组${group}相关的单词创作一个简短的场景描述（中英双语，2-3句话），自然地包含这些单词：${words.join(', ')}
格式：
英文场景：...
中文翻译：...`;
  return await callAI(prompt);
});

// ===== AI: 用词汇讲故事 =====
ipcMain.handle('ai-story-with-words', async (_, group, words, translations) => {
  const wordList = words.map((w, i) => `${w}(${translations[i] || ''})`).join(', ');
  const prompt = `用"${group}"主题词汇写一个生动小故事(100-150字英文)，自然使用每个词：${wordList}
故事后附中文翻译。最后一行：【画面描述】一句英文场景描述(用于AI绘图)。只回复故事。`;
  return await callAI(prompt);
});

// ===== AI: 整理讲稿 =====
ipcMain.handle('ai-lecture', async (_, text) => {
  const prompt = `将以下文本整理为清晰讲稿，分段落，加过渡语，适合朗读：\n\n${text.slice(0, 3000)}`;
  return await callAI(prompt);
});

// ===== AI生成图片 (Pollinations.ai 免费) =====
ipcMain.handle('ai-generate-image', async (_, prompt) => {
  const encoded = encodeURIComponent(prompt);
  const url = `https://image.pollinations.ai/prompt/${encoded}?width=1024&height=768&nologo=true`;
  return url;
});

