// ===== 读取文本文件 =====
ipcMain.handle('read-file-text', async () => {
  const result = await dialog.showOpenDialog(mainWindow, {
    title: '选择文本文件', filters: [{ name: '文本文件', extensions: ['txt', 'md', 'text'] }], properties: ['openFile']
  });
  if (result.canceled || !result.filePaths.length) return null;
  try { return fs.readFileSync(result.filePaths[0], 'utf-8'); } catch(e) { return null; }
});

