ipcMain.handle('get-regulations', () => {
  let data = {};
  try {
    const regPath = app.isPackaged ? path.join(process.resourcesPath, 'regulations.json') : path.join(__dirname, 'regulations.json');
    data = JSON.parse(fs.readFileSync(regPath, 'utf-8'));
  } catch(e) {}
  // 合并用户自定义法规
  if (userDb) {
    try {
      const rows = userDb.prepare('SELECT * FROM user_regulations ORDER BY id').all();
      for (const r of rows) {
        if (!data[r.country_code]) data[r.country_code] = { name: r.country_name, lang: r.country_lang, items: [], _user: true };
        if (!data[r.country_code]._user) data[r.country_code]._user = false; // 内置国家
        data[r.country_code].items.push({ id: r.id, title: r.title, content: r.content, _user: true });
      }
    } catch(e) {}
  }
  return data;
});
